import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient.js';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);

  useEffect(() => {
    fetchDespesas();
  }, []);

  async function fetchDespesas() {
    const { data, error } = await supabase
      .from('compras')
      .select('*')
      .order('data_compra', { ascending: false });
    
    if (error) console.error('Erro:', error);
    else setDespesas(data);
  }

  return (
    <div className="fade-in"> {/* <--- Adicionado aqui */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Minhas Despesas</h2>
        <span style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>
          {despesas.length} registros encontrados
        </span>
      </div>

      <div className="card" style={{ padding: '0', overflowX: 'auto' }}>
  <table>
    <thead>
      <tr>
        <th>Data</th>
        <th>Descrição</th>
        <th>Loja</th>
        <th>Nº Pedido</th>
        <th>Nota Fiscal</th>
        <th>Parcelas</th>
        <th style={{ textAlign: 'right' }}>Valor Total</th>
      </tr>
    </thead>
    <tbody>
      {despesas.map((item) => (
        <tr key={item.id}>
          <td style={{ color: 'var(--text-muted)' }}>
            {new Date(item.data_compra).toLocaleDateString('pt-BR')}
          </td>
          <td style={{ fontWeight: '600' }}>{item.descricao}</td>
          <td>{item.loja || '-'}</td>
          <td style={{ fontFamily: 'monospace', color: 'var(--primary)' }}>
            {item.pedido || '-'}
          </td>
          <td style={{ fontFamily: 'monospace' }}>
            {item.nota_fiscal || '-'}
          </td>
          <td>
            <span style={{ 
              background: item.parcelado ? '#eef2ff' : '#f8fafc', 
              color: item.parcelado ? '#6366f1' : '#64748b',
              padding: '4px 8px', 
              borderRadius: '6px', 
              fontSize: '0.8rem',
              fontWeight: '600',
              border: '1px solid' + (item.parcelado ? '#e0e7ff' : '#e2e8f0')
            }}>
              {item.parcelado ? `${item.num_parcelas}x` : 'À Vista'}
            </span>
          </td>
          <td style={{ fontWeight: '700', textAlign: 'right', color: 'var(--text-main)' }}>
            R$ {parseFloat(item.valor_total).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </td>
        </tr>
      ))}
    </tbody>
  </table>
</div>


    </div>
  );

};

export default Listagem;
